<template>
	<view :class="className" :style="{ height: height, width: width, marginTop: marginTop, }">
		<l-echart ref="chart" @finished="init"></l-echart>
	</view>
</template>

<script>
	import * as echarts from 'echarts'
	//еЕ®йГ®зФµжЬЇзКґжАБзїЯиЃ°
	export default {
		name: 'basic_line_chart',
		props: {
			className: {
				type: String,
				default: 'chart'
			},
			width: {
				type: String,
				default: '100%'
			},
			height: {
				type: String,
				default: '100px'
			},
			autoResize: {
				type: Boolean,
				default: true
			},


			marginTop: {
				type: String,
				default: '10px'
			},
			//ж†ЗзВєжХ∞жНЃ
			legendData: {
				type: Array,
				default: () => [],
			},
			//ж®™иљіеЭРж†З
			xAxisData: {
				type: Array,
				default: () => [],
			},
			//зЇµиљіеЭРж†ЗеАЉ
			series: {
				type: Array,
				default: () => [],
			},
			dayMonth: {
				type: Array,
				default: () => [],
			},
			__that: {
				type: Object,
				default: () => {
					return {};
				},
			},

			//   chartData: {
			//     type: Object,
			//     required: true
			//   }
		},
		data() {
			return {
				myChart: null,
				option: {
					tooltip: {
						trigger: 'item',
						axisPointer: {
							type: 'shadow'
						}
					},
					legend: {
						bottom: '5%',
						// right: 'center',
						// icon: 'rect',//ељҐзКґ  з±їеЮЛеМЕжЛђ circleпЉМrect,lineпЉМroundRectпЉМtriangleпЉМdiamondпЉМpinпЉМarrowпЉМnone
						itemWidth: 8, // иЃЊзљЃеЃљеЇ¶
						itemHeight: 8, // иЃЊзљЃйЂШеЇ¶
						// itemGap: 40, // иЃЊзљЃдЄ§дЄ™legendдєЛйЧізЪДйЧіиЈЭ
						// data:this.legendData,
						data: [{
								name: 'йЂШй£ОйЩ©', // ињЩдЄ™nameйЬАи¶БеТМ series йЗМйЭҐзЪД name еѓєеЇФиµЈжЭ•
								itemStyle: {
									color: '#DF0303', // еНХзЛђиЃЊзљЃжЯРдЄАдЄ™еЫЊеИЧзЪДйҐЬиЙ≤
								},
							},
							{
								name: 'еЕ≥ж≥®', // ињЩдЄ™nameйЬАи¶БеТМ series йЗМйЭҐзЪД name еѓєеЇФиµЈжЭ•
								itemStyle: {
									color: '#FCDF44', // еНХзЛђиЃЊзљЃжЯРдЄАдЄ™еЫЊеИЧзЪДйҐЬиЙ≤
								},
							},
							{
								name: 'ж≠£еЄЄ', // ињЩдЄ™nameйЬАи¶БеТМ series йЗМйЭҐзЪД name еѓєеЇФиµЈжЭ•
								itemStyle: {
									color: '#00CC00', // еНХзЛђиЃЊзљЃжЯРдЄАдЄ™еЫЊеИЧзЪДйҐЬиЙ≤
								},
							},

							{
								name: 'иЙѓе•љ', // ињЩдЄ™nameйЬАи¶БеТМ series йЗМйЭҐзЪД name еѓєеЇФиµЈжЭ•
								itemStyle: {
									color: '#0D08E8', // еНХзЛђиЃЊзљЃжЯРдЄАдЄ™еЫЊеИЧзЪДйҐЬиЙ≤
								},
							},
						]

					},

					grid: {

						left: '10px', // еЫЊељҐиЈЭз¶їеЃєеЩ®еЈ¶иЊєзХМзЪДиЈЭз¶ї
						right: '10px', // еЫЊељҐиЈЭз¶їеЃєеЩ®еП≥иЊєзХМзЪДиЈЭз¶ї
						containLabel: true
					},
					xAxis: {
						type: 'category',
						data: this.xAxisData,
						// data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']

						axisLabel: {
							interval: 0, // иЃЊзљЃеИїеЇ¶йЧійЪФдЄЇ 0пЉМи°®з§ЇжЙАжЬЙеИїеЇ¶йГљжШЊз§Ї
							overflow: 'breakAll', // иґЕеЗЇйГ®еИЖжИ™жЦ≠жШЊз§Ї
						},
					},

					yAxis: {
						type: 'value',
						// interval: 1, // иЃЊзљЃеИїеЇ¶йЧіиЈЭдЄЇжХіжХ∞

						axisLabel: {
							formatter: function(value) {
								if (value === parseInt(value)) {
									return value; // еП™жШЊз§ЇжХіжХ∞

								}
							},
						},
					},
					radius: '100%',
					series: this.series,
					// series: [

					// 	{
					// 		name: 'иЙѓе•љ',
					// 		data: [140, 230, 274, 218, 135, 157, 240],
					// 		type: 'line'
					// 	},
					// 	{
					// 		name: 'ж≠£еЄЄ',
					// 		data: [130, 230, 234, 228, 135, 147, 260],
					// 		type: 'line'
					// 	},
					// 	{
					// 		name: 'еЕ≥ж≥®',
					// 		data: [110, 230, 224, 218, 165, 147, 270],
					// 		type: 'line'
					// 	},
					// 	{
					// 		name: 'йЂШй£ОйЩ©',
					// 		data: [100, 230, 214, 218, 135, 147, 260],
					// 		type: 'line'
					// 	},



					// ]
				},
			}
		},
		mounted() {

			this.$nextTick(() => {
				this.$refs.chart.init(echarts, chart => {
					chart.setOption(this.option);
				});
			})
		},
		beforeDestroy() {
			if (!this.chart) {
				return
			}
			this.chart.dispose()
			this.chart = null
		},
		watch: {
			legendData(newVal) {

				this.option.legend.data = newVal;

				this.$refs.chart.setOption(this.option)
			},
			xAxisData(newVal) {

				this.option.xAxis.data = newVal;

				this.$refs.chart.setOption(this.option)
			},
			series(newVal) {

				this.option.series = newVal;

				this.$refs.chart.setOption(this.option)
			},

		},
		methods: {
			async init() {
				const chart = await this.$refs.chart.init(echarts);
				if (this.option.color && this.option.color.length <= 0) {
					delete this.option['color']
				}
				chart.setOption(this.option)
				var that = this;
				chart.on('click', params => {
					console.log('зВєеЗїдЇЛдїґиІ¶еПС2пЉЪ', params);
					let index = params.dataIndex;
					let time = that.dayMonth[index];
					// uni.$emit('djBarClick', index);
					this.$emit('djTimeClick', time);
					// е§ДзРЖзВєеЗїеЫЮи∞ГзЪДдЄЪеК°йАїиЊС
				});



			},

		}
	}
</script>